988: impl CalcLengthPercentage {
989:     /// Resolves the percentage.
990:     #[inline]
991:     pub fn resolve(&self, basis: Length) -> Length {
992:         // unwrap() is fine because the conversion below is infallible.
993:         if let CalcLengthPercentageLeaf::Length(px) = self
994:             .node
995:             .resolve_map(|leaf| {
996:                 Ok(if let CalcLengthPercentageLeaf::Percentage(p) = leaf {
997:                     CalcLengthPercentageLeaf::Length(Length::new(basis.px() * p.0))
998:                 } else {
999:                     leaf.clone()
1000:                 })
1001:             })
1002:             .unwrap()
1003:         {
1004:             Length::new(self.clamping_mode.clamp(px.px())).normalized()
1005:         } else {
1006:             unreachable!("resolve_map should turn percentages to lengths, and parsing should ensure that we don't end up with a number");
