951:                 }
952: 
953:                 Ok(result)
954:             },
955:             Self::Product(children) => {
956:                 let mut result = children[0].resolve_internal(leaf_to_output_fn)?;
957: 
958:                 for child in children.iter().skip(1) {
959:                     let right = child.resolve_internal(leaf_to_output_fn)?;
